from typing import Protocol

class PaymentProvider(Protocol):
    def charge(self, amount: int) -> bool: ...

class Stripe:
    def charge(self, amount: int) -> bool:
        return True

def checkout(p: PaymentProvider, amount: int) -> bool:
    return p.charge(amount)

from typing import Protocol

class UserRepo(Protocol):
    def add(self, user) -> None: ...
    def get(self, user_id: int): ...

class SqlUserRepo:
    def __init__(self, session):
        self.session = session
    def get(self, user_id):
        return self.session.get(User, user_id)

from fastapi import Depends

def get_repo(session = Depends(get_session)) -> UserRepo:
    return SqlUserRepo(session)

@app.get('/users/{uid}')
async def read(uid: int, repo: UserRepo = Depends(get_repo)):
    return repo.get(uid)

# handler — тонкий адаптер
async def signup_handler(data):
    return await UserService(repo).register(data.email)

